INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989449","title":"Фелл. Град обреченных","author":"Уоррен Эллис,Бен Темплсмит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001383369/140/3cfc/__Fell._Grad_obrechennyh.jpg","isbn":"978-5-91996-068-3","publisher":"XL Media","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Его зовут Ричард Фелл. Он – детектив полиции в мрачном городе Сноутауне, месте, где слова «справедливость» и «закон» не имеют никакого значения. Пытаясь разобраться с призраками прошлого и начать жизнь с чистого листа, Фелл верен лишь одному принципу… ВСЕ ВСЕГДА ЧТО-ТО СКРЫВАЮТ. ДАЖЕ ОН САМ.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999433,"hdCover":""},{"id":"0989448","title":"Классика Marvel. Удивительный Человек-Паук","author":"Стэн Ли,Стив Дитко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785572/140/cd6d/__Klassika_Marvel._Udivitelnyj_ChelovekPauk.jpg","isbn":"978-5-91339-632-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Классика Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":3.5,"review":"","added":9999432,"hdCover":""},{"id":"0989447","title":"Человек-Паук. Нити паутины","author":"Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003354053/140/eede/Gart_Ennis__ChelovekPauk._Niti_pautiny.jpg","isbn":"978-5-04-107444-9","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"О, КАК ЗАПУТАННЫ НИТИ ПАУТИНЫ, ЧТО ОН ПЛЕТЁТ... И здесь вы найдёте истории людей, в неё попавших... от обычных преступников до злодеев в костюмах, от невинных прохожих до потенциальных дам сердца, от старых врагов до новых друзей, от вспыльчивых редакторов газет до сенсационных супергероинь! И каждая история рассказана уникальным голосом комикс-индустрии!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999431,"hdCover":""},{"id":"0989446","title":"The Boys, Vol. 7: The Innocents","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003404276/140/e721/__The_Boys_Vol._7_The_Innocents.jpg","isbn":"978-1606901502","publisher":"Dynamite Entertainment","pubDate":"2010","language":"Английский","series":"The Boys Book Series","genres":["Комиксы","манга","графические романы"],"annotation":"So where are the real superheroes? The warriors for truth and justice, the defenders of the American way, the heroes who fight to make things right and ask for nothing in return? Hughie finds out when he meets the teenage adventurers known as SUPERDUPER... but unknown to the little Scotsman, Butcher has finally learned his secret. A dire scheme is set in motion, and at the vast superhero evangelist festival of BELIEVE, Hughie''s relationship with Annie January - aka Starlight of the Seven - reaches its terrible conclusion. And soon The Boys themselves risk being torn asunder. The Boys, Vol. 7: The Innocents reprints issues 39-47 of the New York Times Best-Selling series by Garth Ennis, Darick Robertson, Russ Braun and John McCrea, and features all of the covers by Robertson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999430,"hdCover":""},{"id":"0989445","title":"The Boys Vol. 6: Self-Preservation Society","author":"Дэрик Робертсон,Гарт Эннис,Джон Маккрэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003404274/140/9b69/__The_Boys_Vol._6_SelfPreservation_Society.jpg","isbn":"978-1606901250, 9781606901250","publisher":"Dynamite Entertainment","pubDate":"2010","language":"","series":"The Boys Book Series","genres":["Комиксы","манга","графические романы"],"annotation":"The sixth Dynamite collection of Garth Ennis and Darick Robertson''s The Boys is here, with The Boys, Vol. 6: Self-Preservation Society! You can only maim and murder so many superheroes before someone decides to do something about it, and in The Boys'' case that means Payback - a superteam of unimaginable power, second only to the mighty Seven. Pulping teenage supes is one thing, but how will our heroes fare against Soldier Boy, Mind-Droid, Swatto, the Crimson Countess, and the Nazi juggernaut known as Stormfront? Blood flies and bones shatter, as Butcher and company meet fire with fire. And in the origin tales of Mother''s Milk, the Frenchman and the Female, Hughie learns of the strange paths by which this disparate trio came to join The Boys. From tragedy in Harlem to the slaughter on the Brooklyn Bridge, from the festival of Les Saints De Haw-Haw to the horror lurking under Tokyo, this is a journey of discovery like no other - with only the flickering lamp of insanity to light the way. The Boys, Vol. 6: Self-Preservation Society collects issues 31-38 of the New York Times Best-Selling series by Garth Ennis, Darick Robertson and Judge Dredd co-creator, Carlos Ezquerra, and features all of the covers by Robertson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999429,"hdCover":""},{"id":"0989444","title":"Guardians of the Galaxy, Vol. 2: Faithless","author":"Донни Кейтс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003830380/140/b73b/Donni_Kejts__Guardians_of_the_Galaxy_Vol._2_Faithless.jpg","isbn":"1302915894, 9781302915896","publisher":"Marvel Comics","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"The death of Rocket! The Guardians of the Galaxy are taking some well-deserved R&R - but their vacation is about to be cut short when a familiar, radically powerful enemy returns. What does all this have to do with everyone''s favorite raccoon-like weapons expert? The bad news is Rocket is dying. But the good news is, he still has some fight left in him! Though with only a few Guardians willing to stand beside him in his final fight...the odds aren''t looking good. Plus: Ever since the Black Order''s attack, several Guardians have been missing in action. Now, find out what really happened to Nova, Quasar, Adam Warlock and Darkhawk! And who better to tell their stories than Cosmo the space dog!  COLLECTING: GUARDIANS OF THE GALAXY 7-12, GUARDIANS OF THE GALAXY ANNUAL (2019) 1","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":3.5,"review":"","added":9999428,"hdCover":""},{"id":"0989443","title":"Пацаны. Том 4. Пора валить","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004165083/140/75ec/__Patsany._Tom_4._Pora_valit.jpg","isbn":"978-5-04-109961-9","publisher":"Fanzon","pubDate":"2020","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Все идет не по плану у команды ренегатов таинственного миллионера Джона Годолкина. Сильвер Кинкейд только что покончила с собой исключительно гротескным образом на глазах изумленной публики. И это плохие новости для франшизы номер один \"\"Войт-Американ\"\", ведь от их успеха зависит то, какой кусок пирога отхватят для себя \"\"Сила Джи\"\", \"\"Берег Джи\"\", \"\"Стиль Джи\"\", \"\"Волшебники Джи\"\", \"\"Британцы Джи\"\" и \"\"Кочевники Джи\"\". Слишком много стоит на кону, чтобы пускать кого-то бродить по Особняку. Кто знает, какие грязные секреты там откопают \"\"Пацаны\"\"? Четвертый том гротескного супергеройского комикса продолжает успешную серию Гарта Энниса с иллюстрациями Дэрика Робертсона. Восемь выпусков-кроссоверов под одной обложкой, мастерски сочетающих криминал и фантастику, пародию, боевик и драму. Издание с галереей альтернативных обложек Дэрика Робертсона и Джона Кэссиди, Говарда Чайкина и Гарри Лича, Стива Диллона и Джима Ли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999427,"hdCover":""},{"id":"0989442","title":"Пацаны. Том 3. Полезно для души","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003994227/140/b83f/__Patsany._Tom_3._Polezno_dlya_dushi.jpg","isbn":"978-5-04-110236-4","publisher":"Fanzon","pubDate":"2020","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Разодетые герои бороздят небеса. Прячут лица за масками самоуправцы. Кто проследит за тем, чтобы суперы не позволили себе лишнего? Встречайте! \"Пацаны\": чрезвычайно опасная команда под эгидой ЦРУ. Билли Бутчер, Малыш Хьюи, Молоко Матери, Француз и Самка.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-09","rating":4.5,"review":"","added":9999426,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989441","title":"Совершенный Человек-Паук. Омнибус","author":"Кристос Гейдж,Дэн Слотт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003265234/140/b1af/__Sovershennyj_ChelovekPauk._Omnibus.jpg","isbn":"978-5-04-106066-4","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отто Октавиус, злодей, также известный как Доктор Осьминог, оказался на пороге смерти. Чтобы обмануть её, он использовал свои навыки безумного учёного и обменялся сознанием со своим величайшим врагом, Питером Паркером, Удивительным Человеком-Пауком. Однако перенос подарил Октавиусу не только могучие способности Человека-Паука, но и всё то, что пережил сам Паркер... в том числе урок о великой ответственности! Теперь Отто Октавиус начинает новую жизнь, жизнь героя... возможно, величайшего героя всех времён. И имя ему - Совершенный Человек-Паук.  В книгу вошли комиксы \"Совершенный Человек-Паук\" #1-31, а также Ежегодники #1-2, написанные Дэном Слоттом и Кристосом Гейджем и проиллюстрированные Райаном Стегманом, Джузеппе Камунколи, Умберто Рамосом, Хавьером Родригезом и многими другими.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999425,"hdCover":""},{"id":"0989440","title":"Удивительный Человек-Паук. Последнее желание","author":"Дэн Слотт,Джен ван Метер,Дематтейс Джон Марк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001488085/140/337e/__Udivitelnyj_ChelovekPauk._Poslednee_zhelanie.jpg","isbn":"978-5-91339-358-6","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"Удивительный Человек-паук","genres":["Комиксы","манга","графические романы"],"annotation":"СМЕРТЬ ЧЕЛОВЕКА-ПАУКА!  Сюжет, успевший за короткое время стать культовым! Обязательно к прочтению для каждого настоящего фаната Человека-Паука.  Доктору Осьминогу осталось жить один год, его тело и мозг деградируют из-за постоянных жестоких побоев, наносимых его заклятым врагом, Человеком-Пауком. Однако гениальный безумец использовал отведённое ему время так, как и можно было предположить. Сначала он мобилизовал армию октоботов и направил их на захват Манхэттена. Затем призвал шесть суперзлодеев, чтобы те похитили сына Нормана Озборна. А потом и вовсе дошло до конца света, так как Осьминог угрожал сжечь планету дотла. И каждый раз его амбициозные планы проваливались. Или нет? Были ли эти поражения очередным доказательством его безумия или же, напротив, его гениальности? Теперь, когда Доктору Осьминогу осталось жить несколько часов, Человек-Паук узнает ответ. Осьминог отплатит ему той же монетой, а последнее желание принесёт гибель Питеру Паркеру и всем, кто ему близок!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999424,"hdCover":""},{"id":"098943f","title":"Карнаж. Полное издание (сборник)","author":"Зеб Уэллс,Рик Спирс,Кристофер Йост,Питер Миллиган,Каллен Банн,Кевин Шиник,Джерри Дагган,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003277009/140/7933/__Karnazh._Polnoe_izdanie_sbornik.jpg","isbn":"","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Карнаж","genres":["Комиксы","манга","графические романы"],"annotation":"Маньяк-симбиот так сильно привлёк внимание, что получил целый сборник всех своих сольных серий... и даже больше!  Начинается всё с потасовки между Карнажем и его «папочкой», Веномом... и становится в разы кровавее, когда Клетус Кэссиди решает отправиться в путешествие по США, оставляя за собой горы трупов! Он сразится с Мстителями, Дэдпулом, Новой, Алым Пауком и новым Веномом, Флэшем Томпсоном! Он станет Совершенным и даже... героем?! И в этом огромном эпике про Карнажа он доберётся до демонической книги «Власть тьмы»!  Сможет ли отряд из Эдди Брока и Джона Джеймсона, бывшего оборотня, остановить Кэссиди, пока тот пытается призвать древнего бога Хтона и устроить конец света?  В сборник вошли выпуски серий «Веном против Карнажа» #1-4, «Карнаж. Семейные распри» #1-5, «Карнаж: С.Ш.А.» #1-5, «Совершенный Карнаж» #1-5, Ежегодник #1, «Ось: Карнаж» #1-3, «Карнаж. Том 2» #1-16, «Веном. Том 2» #26-27, «Алый Паук» #10-11, «Нова. Том 5» #26-27 и два одиночных выпуска из межавторского цикла «Карнаж».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3,"review":"","added":9999423,"hdCover":""},{"id":"098943e","title":"Toxin: The Devil You Know","author":"Питер Миллиган","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003193110/140/7a30/Piter_Milligan__Toxin_The_Devil_You_Know.jpg","isbn":"978-0785118046","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"As each new generation of men must hand down the torch to the next, so each new generation of alien symbiotes must hand down the, ah, stringy, fleshy tendrils. So move over Venom, step aside Carnage, because Toxin is taking the spotlight! When the full-scale jailbreak from the pages of New Avengers leaves New York overrun with super-villains, Pat sees the perfect opportunity to use the creature sharing his body for good. But Toxin might have other ideas! Featuring a special guest appearance by Spider-Man!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3,"review":"","added":9999422,"hdCover":""},{"id":"098943d","title":"Бэтмен. Что случилось с Крестоносцем в Маске?","author":"Нил Гейман,Энди Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002997581/140/f32c/__Betmen._Chto_sluchilos_s_Krestonostsem_v_Maske.jpg","isbn":"978-5-389-16357-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Я умер?» «Еще нет». «Тогда объясни, что происходит». «Ты ведь лучший в мире детектив, Брюс. Может, сам догадаешься?»  Он – защитник Готэма. Его мстительный дух. Его Темный Рыцарь. Много лет он в одиночку ведет войну за чистоту улиц родного города. Но сегодня эта война потребовала свою последнюю – и самую большую – жертву… Самого Бэтмена.  Крестоносец в Маске лежит в гробу в Преступном переулке, в том самом месте, где он и появился на свет. Лучшие друзья и злейшие враги собрались вокруг него, чтобы попрощаться. И каждый рассказывает свою историю о Бэтмене, о том, как он жил…  и как умер.  Как тень в ночи, темная фигура наблюдает за этим зловещим прощанием. Она знает, что эти противоречащие друг другу истории не имеют никакого отношения к истине. И пока не кончится ночь, пока крышка гроба навсегда не отгородит Бэтмена от этого мира, он должен ответить на главный вопрос: ЧТО СЛУЧИЛОСЬ С КРЕСТОНОСЦЕМ В МАСКЕ?  Десятилетия приключений Бэтмена сплелись в одной восхитительной истории. Выдающийся писатель Нил Гейман («Сэндмен», «Коралина» «Американские боги») и суперзвезда мира комиксов Энди Кьюберт («Люди Икс», «Капитан Америка», «Бэтмен») дарят нам проникновенный образ знаменитого комикс-кумира.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999421,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
