FROM json_each('[{"id":"098943c","title":"Batman: Last Knight on Earth","author":"Скотт Снайдер,Грег Капулло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003631553/140/0886/__Batman_Last_Knight_on_Earth.jpg","isbn":"1401294960,  978-1401294960","publisher":"DC Black Label","pubDate":"2020","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"So begins this sprawling tale of the Dark Knight as he embarks on a quest through a devastated DC landscape featuring a massive cast of familiar faces from the DC Universe. As he tries to piece together the mystery of his past, he must unravel the cause of this terrible future and track down the unspeakable force that destroyed the world as he knew it...  From the powerhouse creative team of writer Scott Snyder and artist Greg Capullo, the team that reinvented Batman from the emotional depths of Batman: Court of Owls to the epic power of Dark Nights: Metal, DC Black Label is proud to present what could be the last Batman story ever told...  Collects Batman: Last Knight on Earth #1-3","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999420,"hdCover":""},{"id":"098943b","title":"Человек-Паук: Грусть","author":"Джеф Лоэб,Тим Сейл,Уэс Эбботт,Стив Бучелато","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003634879/140/91fb/__ChelovekPauk_Grust.jpg","isbn":"","publisher":"Параллель Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Человек-Паук: Грусть - это одна из лучших работ легендарного творческого дуэта Джефа Лоэба и Тима Сэйла, посвящённая студенческим годам Питера Паркера, его супергеройской жизни и роковому роману с девушкой, чья трагическая смерть изменила Питера раз и навсегда. Под обложкой Грусти вас ожидает идеальная смесь из романтической мелодрамы и супергеройской хроники, а также трогательная история о юности, любви и боли в мире удивительного Человека-Паука.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999419,"hdCover":""},{"id":"098943a","title":"Халк: Злость","author":"Джеф Лоэб,Тим Сейл,Мэтт Холлингсворт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003272141/140/5ea3/__Halk_Zlost.jpg","isbn":"978-5-6042815-5-0","publisher":"Параллель Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"«Халк: Злость» — это интригующая интерпретация первых дней «рождения» Халка, посвященная мрачным воспоминаниям Брюса Бэннера и его попыткам осмыслить себя с свою «серую» сторону.  Легендарный дуэт Джефа Лоэба и Тима Сэйла поведал в «Злости» историю об отчаянном чудище с душой ребенка, его трагической любви к дочери своего главного преследователя и кровопролитной вражде с миром, который жаждет его смерти.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999418,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
