  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989439","title":"Классические черепашки-ниндзя: Тайна происхождения.","author":"Кевин Истмен,Питер Алан Лерд,Лерд Питер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002144269/140/0dff/__Klassicheskie_cherepashkinindzya_Tajna_proishozhdeniya..jpg","isbn":"978-5-9909197-0-9","publisher":"Illusion Studios","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Благодаря канистре таинственного вещества и чудесному стечению обстоятельств четыре маленьких черепашки и ручная крыса Сплинтер мутировали разумных человекоподобных существ. Сплинтер стал наставником и отцом юных черепашек, обучил их искусству ниндзюцу и дал им имена: Леонардо, Рафаэль, Микеланджело и Донателло. О чём же этот комикс? Постоянная ночь, полумрак канализацонных стоков, неприветливые проулки и промозглые крыши города, бессердечные уличные банды и рассчетливый враг в острых как бритва латах, поджидающий в конце истории. Так начинается история о мести, чести и достоинстве. И пусть главными героями выступают странные создания, далеко не люди, их облик настолько живой и яркий, что поневоле начинаешь сочувствовать их образу жизни, сопереживать их испытаниям, восхищаться их стойкостью и непоколебимостью. Такой образ сотворили Кевин Истмен и Питер Лерд, в противовес красивым и статным супергероям мейнстрима. Их четвёрка мутантов сумела завоевать сердца миллионов читателей во всём мире. Тогда их не знал никто. Теперь же, тридцать лет спустя, их знают все! Познакомьтесь с настоящими Черепашками-Ниндзя, которые сумели проложить этот путь, чтобы в конечном счете сойти со страниц комиксов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999417,"hdCover":""},{"id":"0989438","title":"Капитан Америка: Скорбь","author":"Джеф Лоэб,Тим Сейл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003272144/140/194c/__Kapitan_Amerika_Skorb.jpg","isbn":"978-5-6042815-1-2","publisher":"Параллель Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Капитан Америка: Скорбь» — это ураганные приключения и военная драма в одном флаконе, проливающим свет на неизлечимую боль в сердце стража свободы.  Мастерский тандем Джефа Лоэба и Тима Сэйла повествует в «Скорби» о непростых отношениях Стива Роджерса и Баки Барнса, а также душевных муках героя, потерявшего родственную душу на поле боя.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999416,"hdCover":""},{"id":"0989437","title":"Эра Альтрона. Книга 2","author":"Брайан Майкл Бендис,Карлос Пачеко,Брэндон Петерсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001421775/140/4219/__Era_Altrona._Kniga_2.jpg","isbn":"978-5-9906867-2-4","publisher":"Jellyfish Jam","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Наступила Эра Альтрона. Мрачное будущее, где мир захватил зловещий искусственный интеллект. Сотни героев погибли, уцелевшие вынуждены скрываться. Злодей недостижим, он наносит удары из будущего. У человечества остался последний шанс - машина времени на секретной базе Ника Фьюри. Команда самых могучих героев Земли отправляется в будущее на решающий бой с Альтроном. Но Росомаха не верит в их успех, но возвращается в прошлое, чтобы раз и навсегда покончить с создателем Альтрона- мстителем Хэнком Пимом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999415,"hdCover":""},{"id":"0989436","title":"Эра Альтрона. Книга 1","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001337306/140/3fb8/Brajan_Majkl_Bendis__Era_Altrona._Kniga_1.jpg","isbn":"978-5-9906867-0-0","publisher":"Jellyfish Jam","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Долгие годы искусственный интеллект Альтрон стремился уничтожить человечество. И сейчас ему это удалось. Уцелела лишь горстка героев, и те вынуждены скрываться от вездесущих роботов Альтрона. Чтобы спастись, Капитану Америка и его команде придется пойти на радикальные меры, но не все с ними согласны...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999414,"hdCover":""},{"id":"0989435","title":"Дэдпул. Marvel NOW! Омнибус","author":"Джерри Дагган","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004046646/140/0fc0/Dzherri_Daggan__Dedpul._Marvel_NOW_Omnibus.jpg","isbn":"978-5-04-107454-8","publisher":"Эксмо, Комильфо","pubDate":"2020","language":"Русский","series":"Дэдпул. Полные издания","genres":["Комиксы","манга","графические романы"],"annotation":"Ваши новые любимые сценаристы \"Дэдпула\" протащили болтливого наёмника через полный спектр эмоций в одном огромном сборнике, где есть буквально всё. Комедия, трагедия и всё, что между: рождение (ну, типа), свадьба (вы приглашены!) и куча смертей. История начинается с зомби-президентов и становится лишь безумнее, бросая Уэйда Уилсона в различные невероятные места, вместе с этим показывая неизвестные ранее приключения из разных периодов его прошлого. Вы увидите много хорошего, плохого и неописуемо ужасного. Встретите новых друзей, старых друзей и королеву-суккуба, которая хочет быть не просто другом. А также ваши пути пересекутся с такими героями, как Капитан Америка и Росомаха, и злыднями вроде Мефисто и Дракулы! И благодаря всему этому вам удастся глубоко проникнуть в мрачные уголки мозга Дэдпула... Приготовьтесь к ужасам, что подстерегают вас там! Если кому и суждено было встретиться, задружиться и написать \"Дэдпула\", так это Джерри Даггану и Брайну Посэну!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999413,"hdCover":""},{"id":"0989434","title":"Новые мутанты","author":"Фабиан Нициеза,Роб Лайфилд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003015541/140/99cd/__Novye_mutanty.jpg","isbn":"978-5-69673-8","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Рэй Брэдбери","genres":["Комиксы","манга","графические романы"],"annotation":"Представляем вам сингл \"Новые мутанты\" #98. Этот комикс поистине можно считать культовым, так как именно в нем впервые появился один из самых популярных персонажей вселенной Marvel - Дэдпул! Уже тогда он был абсолютно безумен и мозгосшибателен. А также встречайте специальных гостей: загадочного Гидеона и неудержимую Домино!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999412,"hdCover":""}]');

