  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989433","title":"Стражи Галактики. Том 2","author":"Дэн Абнетт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002971337/140/8e48/Den_Abnett__Strazhi_Galaktiki._Tom_2.jpg","isbn":"978-5-6041718-4-4","publisher":"Jellyfish Jam","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Обновленный и расширенный состав Стражей пытается удержать галактику от буквального распада... вот только никто не собирается делать их жизнь проще: на этот раз очередную войну развязали межзвездные империи Шиар и Крии, а Вселенская Церковь Истины хочет отомстить команде за прошлые поражения. И если всё продолжится теми же темпами, то очень скоро Стражам Галактики нечего будет сторожить. Так что нас вновь ждут супергеройские приключения, грандиозные бои в космосе и даже путешествия во времени!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999411,"hdCover":""},{"id":"0989432","title":"Современный Человек-Паук. Том 2","author":"Брайан Майкл Бендис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005373840/140/3419/Brajan_Majkl_Bendis__Sovremennyj_ChelovekPauk._Tom_2.jpg","isbn":"978-5-6043127-2-8","publisher":"Зодиак","pubDate":"2020","language":"","series":"Современный Человек-Паук","genres":[],"annotation":"Майлз Моралес всё ещё привыкает к жизни Человека-паука, когда Капитан Америка делает ему особое предложение. Майлз действительно вступит в Алтимэйтс? Пока израненная страна от Гражданской Войны взывает к героям за помощью, Майлз полон решимости доказать, что как никто другой способен помочь.  А когда зловещий новый симбиот Веном появляется, вооружённый правдой об инциденте, давшем новому Человеку-пауку силы, Паучок обзаводится своим первым настоящим заклятым врагом.  В состав сборника вошли выпуски Современный Человек-паук #13-28 и 16.1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999410,"hdCover":""},{"id":"0989431","title":"Guardians of the Galaxy, Vol. 1: The Final Gauntlet","author":"Донни Кейтс,Джефф Шоу","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003189818/140/ce79/__Guardians_of_the_Galaxy_Vol._1_The_Final_Gauntlet.jpg","isbn":"1302915886, 9781302915889","publisher":"Marvel","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"WHO WILL STAND? The universe is on fire. Hundreds of worlds are at war. Never has there been such hatred and division across the cosmos. And in spite of all this, Thanos of Titan is still dead...or is he? Now, more than ever, the cosmos need the Guardians of the Galaxy...but in the aftermath of the Infinity Wars, who is left to answer the call? Featuring every cosmic super hero in the known universe by the THANOS WINS creative team of Donny Cates and Geoff Shaw!  COLLECTING: GUARDIANS OF THE GALAXY 1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999409,"hdCover":""},{"id":"0989430","title":"Бэтмен: Ноэль (сборник)","author":"Ли Бермехо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001454505/140/edb8/Li_Bermeho__Betmen_Noel_sbornik.jpg","isbn":"978-5-389-10387-0","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Пока Темный Рыцарь преследует своего самого заклятого врага по заснеженным просторам Готэма, серия причудливых событий грозит погубить его душу… навеки.  Написанный и нарисованный суперзвездой мира комиксов Ли Бермехо «Бэтмен: Ноэль» споет читателю совсем иную песнь в Сочельник.  Особенностью нашего издания служит включенная в книгу «Рождественская песнь» Чарльза Диккенса, послужившая источником вдохновения и богатых реминисценций для «Бэтмен: Ноэль». Ибо «глубоко в человеческом сердце заложена страсть кого-нибудь преследовать», как сказал Чарльз Диккенс.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999408,"hdCover":""},{"id":"098942f","title":"Дэдпул. Испытание Дракулы","author":"Брайан Позен, Джерри Дагган","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002728769/140/314c/Brajan_Pozen_Dzherri_Daggan__Dedpul._Ispytanie_Drakuly.jpg","isbn":"978-5-91339-577-1","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Наступил закат холостой жизни Уэйда Уилсона. Однако в этой истории сияют и искрятся только диалоги. Дракула выбрал себе невесту. Она королева нежити и по совместительству суккуб. Их союз должен положить конец извечной войне и подарить Дракуле власть над всем миром монстров. Есть лишь одна проблемка: чтобы привести невесту, он нанял Дэдпула. Ставки высоки, но затем они стремительно падают, пока гнусный Уэйд играет в Индиану Джонса, выкапывая давно уже похороненную суженую Дракулы. Но, сражаясь с телепортирующими асассинами, греческими легендами и Блэйдом, охотником на вампиров, он параллельно начинает понимать, что не все рады этому нечестивому браку. И когда Дэдпул наконец встречает наречённую, даже он начинает сомневаться. Если Уэйд не пройдёт эту полосу, Дракула сделает так, что препятствия станут непреодолимыми. А это значит, что он отправит Ночного Оборотня и Ужасающую в прямом смысле Четвёрку, дабы вернуть невесту. Бал монстров в самом разгаре, как далеко зайдёт Уэйд, чтобы остановить эту свадьбу?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3,"review":"","added":9999407,"hdCover":""},{"id":"098942e","title":"Дэдпул против Карнажа","author":"Банн Каллен,Ким Ясинто,Сальвадор Эспин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002077822/140/004d/__Dedpul_protiv_Karnazha.jpg","isbn":"978-5-91339-470-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Два психопата в красном по цене одного! Эй, все сюда! На самое кровавое представление в истории вселенной Marvel! Клетус Кэссиди за решёткой, а симбиот Карнаж в карантине! Но мы все знаем, что это не навсегда, верно? Клетуса изучали, держали взаперти и даже подвергли лоботомии. С Карнажа брали пробы, клонировали, тыкали и кололи. Хватит! Пора снова собраться вместе! Размажет ли Карнаж Дэдпула по всему пейзаж? Или Дэдпул заболтает красного социопата до смерти? Узнайте в этой потасовке века, пропитанной кровью! Это возвращение к кровавой, жестокой форме самого опасного убийцы во вселенной Marvel!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":2.5,"review":"","added":9999406,"hdCover":""},{"id":"098942d","title":"Доктор Стрэндж: в Ад и обратно (сборник)","author":"Майк Миньола,Брендан Маккарти,Роджер Стерн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002077136/140/259f/__Doktor_Strendzh_v_Ad_i_obratno_sbornik.jpg","isbn":"978-5-00028-110-9","publisher":"Parallel Comics","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Доктор Стивен Стрэндж — верховный волшебник вселенной Marvel и один из самых загадочных супергероев. У него нет сверхсил, он не пускает из рук паутину и не правит королевством. Но он всегда готов прийти на помощь и самоотверженно спасти мир — и заодно других, более приземлённых героев.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999405,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098942c","title":"Легенды","author":"Пол Дженкинс,Паоло Ривера","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001604872/140/db66/__Legendy.jpg","isbn":"978-5-00028-101-7","publisher":"Marvel, Parallel Comics","pubDate":"2016","language":"Русский","series":"Marvel - Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"Человек-Паук, Фантастическая четвёрка, Призрачный гонщик, Люди Икс, Халк, Капитан Америка... Персонажи Marvel. Легенды нашего времени.  Миллионы людей по всему миру покорены историями об их свершениях, сравнимыми с деяниями героев Древней Греции. Однако настоящие супергерои – намного значимее собственных подвигов. Кто же они на самом деле?  «Легенды» — это новое прочтение классических историй о появлении знаменитых персонажей. Шесть версий великого мифа о происхождении героя, погруженных в современный культурный контекст. Лауреат Премии Айснера Пол Дженкинс (Origin, Inhumans) искусно переделал известные сюжеты, а благодаря бесподобному Паоло Ривере («Сорвиголова») они в буквальном смысле заиграли новыми красками.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999404,"hdCover":""},{"id":"098942b","title":"Вижн","author":"Габриэль Эрнандес Вальта,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004757769/140/fb0d/__Vizhn.jpg","isbn":"978-5-04-114174-5","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Золотая коллекция Marvel","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Вижн хочет быть человеком, а что характеризует тебя как человека лучше, чем семья? Так что он направляется туда, где всё началось: в лабораторию, где Альтрон создал его и превратил в оружие. Место, где он впервые воспротивился дарованной судьбе и решил, что способен стать чем-то большим - способен стать человеком. Там он и создал их. Жену, Вирджинию. Двух близняшек-подростков, Вив и Вина. Они выглядели как он. У них были его силы. Они разделяли его отчаянное стремление (или же одержимость) стать нормальными. Эта семья живёт по соседству и способна убить всех нас. Что может пойти не так? Искусственные сердца будут разбиты, тела не удастся похоронить, а правду - скрыть. Вижн никогда не будет прежним. Этим комиксом Том Кинг показал, что для создания гениальной истории совершенно необязательно иметь в распоряжении знаменитого персонажа, и вписал своё имя в историю индустрии. Кинг, до карьеры в комиксах работавший в ЦРУ, выстраивает тонкий психологический триллер, показывает, как из-за опрометчивых решений идеальная с виду семейная жизнь может превратиться в кошмар, который не под силу выдержать даже синтезоиду, не раз спасавшему мир вместе с Мстителями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4.5,"review":"","added":9999403,"hdCover":""},{"id":"098942a","title":"Marvel Comics #1000","author":"Эл Юинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004692234/140/1a29/El_Yuing__Marvel_Comics_1000.jpg","isbn":"978-5-04-111622-4","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Золотая коллекция Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"Восемьдесят лет! Множество легендарных художников и сценаристов! Одна история! Чтобы отпраздновать юбилей издательства Marvel, самые известные люди индустрии комиксов (и не только!) собрались вместе, чтобы рассказать о своих любимых героях и злодеях прошлого, настоящего — и даже будущего! К работе над юбилейным выпуском было привлечено 80 авторских команд из настоящих звёзд индустрии комиксов, кино и литературы — итогом работы каждой стала страница, посвящённая тому или иному персонажу или событию. На страницах Marvel Comics #1000 Джонатан Хикман берётся за Людей Икс, Крис Клэрмонт и Эрик Ларсен возвращаются к своим любимым героям, Джейсон Аарон выдаёт потрясающий тим-ап Росомахи и Карателя, Джеф Лоэб и Тим Сэйл вновь объединяются для создания пародийного комикса в духе \"Что за?!..\" и многое, многое другое. И объединяющей все эти сюжеты нитью становится история Эла Юинга (\"Бессмертный Халк\", \"Локи. Агент Асгарда\") о Маске Вечности и тайном заговоре, корнями уходящем в далёкую древность. Каждая страница сборника — это история от одной из приглашённых звёзд, а всё вместе – одно большое событие, которое вот-вот перевернёт Вселенную Marvel и начнёт новую удивительную главу в истории издательства!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999402,"hdCover":""},{"id":"0989429","title":"Смерть Росомахи","author":"Стив МакНивен,Чарльз Соул","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001488757/140/9000/__Smert_Rosomahi.jpg","isbn":"978-5-91339-359-3","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Логан, также известный как Росомаха, был рождён с удивительными способностями — сверхострыми когтями, обострёнными чувствами и исцеляющим фактором, позволяющим его телу регенерировать после любых, даже самых страшных ранений. Но теперь он потерял исцеляющий фактор, а значит, стал смертным. Все дороги куда-нибудь приводят, и история каждого героя рано или поздно подходит к концу. Для Росомахи это время уже настало. Успеет ли Росомаха узнать личность своего врага? или ему суждено сгинуть в череде бесконечных битв? Величайший участник команды «Люди Икс» окажется в центре уникальной истории, которой предстоит стать главным событием в его жизни!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":3.5,"review":"","added":9999401,"hdCover":""},{"id":"0989428","title":"Бэтмен. Detective Comics #1000","author":"Скотт Снайдер,Джим Ли,Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003184753/140/456a/__Betmen._Detective_Comics_1000.jpg","isbn":"978-5-389-17009-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Над этим юбилейным суперкомиксом работала целая плеяда знаменитейших творцов как западной комикс-индустрии (Скотт Снайдер, Грег Капулло, Джим Ли, Том Кинг, Тони С.Дэниел, Пол Дини, Джефф Джонс, Брайан Майкл Бендис, Джеймс Тайнион IV и многие другие), так и отечественной – переводчиками 11 основных историй выступили Арсений Дубаков, Игорь «Дитрих» Кислицын, Кирилл Кутузов, Беата Коташевская, Иван Чернявский, Александр Куликов, Алексей Волков, Руслан Хубиев, Василий Кистяковский, Всеволод Нежданов, а также наш главный редактор, большой любитель комиксов и манги, Александр Жикаренцев. Создатели 1000-го выпуска рисуют Бэтмена в различных ипостасях – первоклассного детектива, охотника за сокровищами и искателя приключений, борца с преступностью, доброго отца и рыцаря.  В комиксе появятся знакомые нам антагонисты – Загадочник, Пингвин, Бэйн, Мистер Фриз, Пугало, Харли Квинн, ну и Джокер. Где Бэтмен, там и Джокер.  Вас ждет масса увлекательных приключений!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999400,"hdCover":""}]');
